import{_ as a,a as r,b as t,c as d}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as s,o as i,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Sauvegarde redondante et source de lecture","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Other/redundant-backup-and-read-source.md","filePath":"fr-FR/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),u={name:"fr-FR/Other/redundant-backup-and-read-source.md"};function o(c,e,p,h,g,m){return i(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="sauvegarde-redondante-et-source-de-lecture" tabindex="-1">Sauvegarde redondante et source de lecture <a class="header-anchor" href="#sauvegarde-redondante-et-source-de-lecture" aria-label="Permalink to &quot;Sauvegarde redondante et source de lecture&quot;">​</a></h1><p>La sauvegarde redondante crée une copie supplémentaire de fichiers déjà envoyés.</p><p>Pour les visiteurs, le fichier principal et sa copie se comportent de la même manière. La différence concerne uniquement le canal de stockage depuis lequel le fichier est lu.</p><h2 id="ce-que-cela-permet" tabindex="-1">Ce que cela permet <a class="header-anchor" href="#ce-que-cela-permet" aria-label="Permalink to &quot;Ce que cela permet&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonction</th><th>Description</th></tr></thead><tbody><tr><td>Conserver une copie supplémentaire</td><td>Copie le fichier vers un autre canal pour réduire la dépendance à un seul stockage</td></tr><tr><td>Changer la source de lecture</td><td>Alterne entre le canal principal et le canal de sauvegarde</td></tr><tr><td>Sauvegarder un fichier</td><td>Crée une copie depuis la fiche d’un fichier</td></tr><tr><td>Sauvegarder par lot</td><td>Sélectionne plusieurs fichiers dans le panneau et les copie ensemble</td></tr><tr><td>Compléter les sauvegardes</td><td>Ajoute des sauvegardes par dossier depuis Autres paramètres</td></tr></tbody></table><h2 id="ou-configurer" tabindex="-1">Où configurer <a class="header-anchor" href="#ou-configurer" aria-label="Permalink to &quot;Où configurer&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Autres paramètres -&gt; Sauvegarde redondante</span></span></code></pre></div><p><img src="'+a+'" alt="Sauvegarde redondante" loading="lazy"></p><p>Vous pouvez compléter les sauvegardes pour un dossier précis ou pour tous les fichiers. Le canal de sauvegarde peut être choisi manuellement ou laissé en mode automatique.</p><h2 id="sauvegarder-depuis-le-detail-d-un-fichier" tabindex="-1">Sauvegarder depuis le détail d’un fichier <a class="header-anchor" href="#sauvegarder-depuis-le-detail-d-un-fichier" aria-label="Permalink to &quot;Sauvegarder depuis le détail d’un fichier&quot;">​</a></h2><p>Dans le panneau, ouvrez le détail d’un fichier et lancez la sauvegarde.</p><p><img src="'+r+'" alt="Sauvegarde depuis le détail" loading="lazy"></p><p>C’est pratique pour protéger ponctuellement un fichier important. Une fois la sauvegarde réussie, le détail du fichier affiche les sources de lecture disponibles.</p><h2 id="sauvegarde-par-selection" tabindex="-1">Sauvegarde par sélection <a class="header-anchor" href="#sauvegarde-par-selection" aria-label="Permalink to &quot;Sauvegarde par sélection&quot;">​</a></h2><p>Dans le panneau, sélectionnez plusieurs fichiers et lancez une sauvegarde par lot.</p><p><img src="'+t+'" alt="Sauvegarde par lot" loading="lazy"></p><p>La sauvegarde depuis le détail, la sauvegarde par sélection et la sauvegarde redondante depuis Autres paramètres utilisent la même logique ; seul le point d’entrée change.</p><h2 id="changer-la-source-de-lecture" tabindex="-1">Changer la source de lecture <a class="header-anchor" href="#changer-la-source-de-lecture" aria-label="Permalink to &quot;Changer la source de lecture&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Description</th></tr></thead><tbody><tr><td>Canal principal</td><td>Lit depuis le canal utilisé lors du premier upload</td></tr><tr><td>Canal de sauvegarde</td><td>Lit depuis le canal où la copie a été enregistrée</td></tr></tbody></table><p><img src="'+d+'" alt="Changer la source" loading="lazy"></p><p>Après changement, les images, vidéos et liens de téléchargement continuent à fonctionner normalement avec la source choisie.</p><h2 id="cas-ignores" tabindex="-1">Cas ignorés <a class="header-anchor" href="#cas-ignores" aria-label="Permalink to &quot;Cas ignorés&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cas</th><th>Raison</th></tr></thead><tbody><tr><td>Sauvegarde déjà existante</td><td>Évite de dupliquer inutilement l’espace</td></tr><tr><td>Canal principal identique au canal de sauvegarde</td><td>Copier dans le même canal n’apporte pas de redondance</td></tr><tr><td>Aucun canal disponible</td><td>Aucun autre canal adapté n’a été trouvé</td></tr></tbody></table><h2 id="lors-de-la-suppression" tabindex="-1">Lors de la suppression <a class="header-anchor" href="#lors-de-la-suppression" aria-label="Permalink to &quot;Lors de la suppression&quot;">​</a></h2><p>Lorsque vous supprimez un fichier, ImgBed supprime à la fois le fichier principal et sa copie de sauvegarde.</p>',25)])])}const _=s(u,[["render",o]]);export{b as __pageData,_ as default};
